function.body:
-- Logistice
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Result NUMBER:=1; -- 0=failure
    v_count NUMBER:=0; -- 0=failure
    v_Record_ID VARCHAR2(32);
    v_User_ID VARCHAR2(32):='0';

    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Record RECORD;

BEGIN

    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);

    BEGIN --BODY
        -- Get Parameters
        v_ResultStr:='ReadingParameters';
        FOR Cur_Parameter IN (
            SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date
            FROM AD_PInstance i
                LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID
            WHERE i.AD_PInstance_ID = P_Instance_ID
            ORDER BY p.SeqNo
        ) LOOP
            v_Record_ID := Cur_Parameter.Record_ID;
            v_User_ID := Cur_Parameter.AD_User_ID;
        END LOOP; -- Get Parameter

        --Delete old lines
        DELETE FROM sdc_dc_propocollect WHERE sdc_debitcollect_id = v_Record_ID;

        SELECT * INTO Cur_Record FROM sdc_debitcollect WHERE sdc_debitcollect_id = v_Record_ID;

        INSERT INTO sdc_dc_propocollect(
            sdc_dc_propocollect_id, ad_org_id,ad_client_id,   
            createdby, updatedby, c_bpartner_id, documentno, duedate, 
            shareno, outstandingamt, sdc_debitcollect_id, fin_payment_schedule_id)
        SELECT get_uuid,Cur_Record.ad_org_id, Cur_Record.ad_client_id,
            v_User_ID, v_User_ID, c_bpartner_id,documentno,expecteddate
            ,shareno,outstandingamt, head_id,fin_payment_schedule_id 
            FROM (SELECT get_uuid(), i.c_bpartner_id,i.documentno,ps.expecteddate
                ,coalesce(em_ssppi_shareno,0) shareno,ps.outstandingamt,v_Record_ID head_id, ps.fin_payment_schedule_id
                ,ROW_NUMBER() OVER (PARTITION BY i.c_invoice_id ORDER BY documentno,expecteddate ASC) rn
            FROM c_invoice i
                JOIN c_doctype dc ON dc.c_doctype_id=i.c_doctype_id
                JOIN fin_payment_schedule ps ON ps.c_invoice_id=i.c_invoice_id
                JOIN c_bpartner bp ON bp.c_bpartner_id=i.c_bpartner_id
                JOIN (SELECT
                    i.c_invoice_id,
                    MIN(ps.expecteddate),
                    MIN(ps.expecteddate) BETWEEN TRUNC(Cur_Record.acredit_date_from) AND TRUNC(last_day(Cur_Record.acredit_date)) as valid_invoice
                FROM
                    c_invoice i
                    JOIN c_doctype dc ON dc.c_doctype_id = i.c_doctype_id
                    JOIN fin_payment_schedule ps ON ps.c_invoice_id = i.c_invoice_id
                WHERE
                    i.issotrx = 'Y'
                    AND ps.outstandingamt <> 0
                    AND docstatus = 'CO'
                    AND dc.isreversal = 'N'
                    AND dc.isreturn = 'N'
                GROUP BY
                    i.c_invoice_id) iv ON iv.c_invoice_id = i.c_invoice_id AND iv.valid_invoice = true
            WHERE i.issotrx='Y' 
                AND ps.outstandingamt <> 0 
                AND TRUNC(ps.expecteddate) BETWEEN TRUNC(Cur_Record.acredit_date_from) AND TRUNC(last_day(Cur_Record.acredit_date))
                AND docstatus='CO'
                AND dc.isreversal = 'N' AND dc.isreturn = 'N' 
                AND bp.em_sdc_last_confirmation IS NOT NULL
              AND bp.em_sdc_last_confirmation BETWEEN TRUNC(Cur_Record.acredit_date_from) AND TRUNC(Cur_Record.acredit_date)
                AND CASE WHEN Cur_Record.typeload = 'RPH' THEN em_sdc_collections='Y'
                        WHEN Cur_Record.typeload = 'DOPH' THEN em_sdc_otherdebits='Y'
                        WHEN Cur_Record.typeload = 'DPH' THEN em_sdc_debits='Y' ELSE false END
            ORDER BY documentno,expecteddate) x
        WHERE CASE WHEN Cur_Record.condition = 'MO' THEN x.rn=1 ELSE 1=1 END;

        --Sdc_load_lines - Finish_Process Extension Point
        SELECT count(*) INTO v_count
        FROM DUAL
        where exists (select 1 from ad_ep_procedures where ad_extension_points_id = 'D304FC7CBFDF4FDF95B553D7E4085FB8');
        IF (v_count=1) THEN
            DECLARE
                v_ep_instance VARCHAR2(32);
                v_extension_point_id VARCHAR2(32) := 'D304FC7CBFDF4FDF95B553D7E4085FB8';
            BEGIN
                v_ep_instance := get_uuid();
                AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Record_ID',
                v_record_id, NULL, NULL, NULL, NULL, NULL, NULL);
                AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'User',
                v_User_ID, NULL, NULL, NULL, NULL, NULL, NULL);
                AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Message',
                NULL, NULL, NULL, NULL, NULL, NULL, v_Message);
                AD_EP_INSTANCE_PARA_INSERT(v_ep_instance, v_extension_point_id, 'Result',
                NULL, NULL, v_result, NULL, NULL, NULL, NULL);
                AD_EXTENSION_POINT_HANDLER(v_ep_instance, v_extension_point_id);
                SELECT p_number INTO v_Result
                FROM ad_ep_instance_para
                WHERE ad_ep_instance_id = v_ep_instance
                AND parametername LIKE 'Result';
                SELECT p_text INTO v_Message
                FROM ad_ep_instance_para
                WHERE ad_ep_instance_id = v_ep_instance
                AND parametername LIKE 'Message';

                DELETE FROM ad_ep_instance_para
                WHERE ad_ep_instance_id = v_ep_instance;
            END;
        END IF;

        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message);
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);

        RETURN;
    END; --BODY

    EXCEPTION WHEN OTHERS THEN
        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE( v_ResultStr) ;
        ROLLBACK;
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr);
END SDC_LOAD_LINES
